162→function LoggedInShell({children}: {children: React.ReactNode}) {
163→  const {session} = useAuth();
164→  const userId = session?.user.id;
165→  const [toast, setToast] = useState<{message: string; visible: boolean}>({
166→    message: '',
167→    visible: false,
168→  });
169→
170→  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
171→    const message =
172→      (payload.message as string) || 'You have a new notification';
173→    setToast({message, visible: true});
174→  }, []);
175→
176→  const handleDismissToast = useCallback(() => {
177→    setToast(prev => ({...prev, visible: false}));
178→  }, []);
179→
180→  useRealtimeNotifications(userId, {
181→    onNewNotification: handleNewNotification,
182→  });
183→
184→  return (
185→    <View style={styles.shellContainer}>
186→      {children}
187→      <Toast
188→        message={toast.message}
189→        visible={toast.visible}
190→        onDismiss={handleDismissToast}
191→        type="info"
192→      />
193→    </View>
194→  );
195→}
